rules:
@media only screen and (max-width: 768px) {
  .interface-wrapper { width: 100%; top: 24px; left: 24px; }
  .icon-control-container { height: 19.5px; width: 19.5px; }
}

@keyframes jittery { 
  10% { transform: translate(-0.1px, -0.15px) scale(1, 1); }
  20% { transform: translate(0.15px, 0.1px) scale(1, 1); }
  30% { transform: translate(-0.2px, -0.25px) scale(1, 1); }
  40% { transform: translate(0.05px, 0.1px) scale(1, 1); }
  50% { transform: translate(-0.025px, -0.05px) scale(1, 1); }
  60% { transform: translate(0px, 0.075px) scale(1, 1); }
  70% { transform: translate(-0.075px, -0.1px) scale(1, 1); }
  80% { transform: translate(0.075px, 0.125px) scale(1, 1); }
  90% { transform: translate(-0.125px, -0.075px) scale(1, 1); }
  100% { transform: translate(0.075px, 0.025px) scale(1, 1); }
}

@media only screen and (max-width: 768px) {
  h1, h2, h3, h4, h5, p { font-size: 10px; }
}

@keyframes dotty { 
  0% { content: "   "; }
  25% { content: ". "; }
  50% { content: ".. "; }
  75% { content: "..."; }
  100% { content: "   "; }
}

@keyframes blink { 
  0%, 100% { background-color: transparent; }
  50% { background-color: white; }
}

@-webkit-keyframes blink { 
  0%, 100% { background-color: transparent; }
  50% { background-color: white; }
}

@media only screen and (max-width: 768px) {
  .loading-screen-header { padding: 16px; }
  .info-wrapper { top: 16px; left: 16px; }
  .blinking-cursor { background-color: rgb(255, 255, 255); width: 0.4em; height: 0.08em; animation: 0.65s step-end 0s infinite normal none running blink; }
  .loading-screen-body { padding-left: 16px; padding-right: 16px; }
  .loading-screen-footer { padding: 16px 16px 32px; }
}
